import{_ as i,o as e,c as s,a2 as t}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Codex 生图教程","description":"","frontmatter":{},"headers":[],"relativePath":"guide/codex-image.md","filePath":"guide/codex-image.md","lastUpdated":null}'),l={name:"guide/codex-image.md"};function p(n,a,o,d,h,c){return e(),s("div",null,[...a[0]||(a[0]=[t(`<h1 id="codex-生图教程" tabindex="-1">Codex 生图教程 <a class="header-anchor" href="#codex-生图教程" aria-label="Permalink to &quot;Codex 生图教程&quot;">​</a></h1><p>CCWS Codex Image Skill 可以让 Codex 在生图、图片编辑、图生图、局部修改和背景替换等任务中调用 CCWSPro 的生图模型。</p><p>开始前请先准备好：</p><ul><li>已完成 <a href="/guide/codex">Codex 配置</a>，并确认 Codex 可以正常对话。</li><li>已在 CCWSPro 控制台创建可用于生图的 API Key。</li><li>本机已安装 Python。macOS / Linux 通常使用 <code>python3</code>，Windows 通常使用 <code>py -3</code>。</li></ul><div class="tip custom-block"><p class="custom-block-title">适用场景</p><p>如果你希望在 Codex 里直接说“帮我生成一张图”“把这张图改成某种风格”“替换图片背景”，就可以安装这个生图技能。</p></div><h2 id="_1-获取生图-api-key" tabindex="-1">1. 获取生图 API Key <a class="header-anchor" href="#_1-获取生图-api-key" aria-label="Permalink to &quot;1. 获取生图 API Key&quot;">​</a></h2><p>进入 CCWSPro 控制台，创建生图分组 API Key，并确认这个 Key 支持：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>model: gpt-image-2</span></span></code></pre></div><p>创建后复制 API Key，并保存到本地安全位置。不要把 API Key 发到聊天窗口、截图、群聊或公开仓库中。</p><h2 id="_2-下载安装包" tabindex="-1">2. 下载安装包 <a class="header-anchor" href="#_2-下载安装包" aria-label="Permalink to &quot;2. 下载安装包&quot;">​</a></h2><p>打开 <a href="https://github.com/xiaofengtongxue-lab/ccws-codex-image-skill/releases" target="_blank" rel="noreferrer">CCWS Codex Image Skill Releases</a>，下载最新版本的安装包。</p><p>安装包文件名通常类似：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ccws-image-generation-installer-v版本号.zip</span></span></code></pre></div><p>下载后解压到一个你能找到的位置，例如桌面或下载目录。</p><h2 id="_3-配置环境变量" tabindex="-1">3. 配置环境变量 <a class="header-anchor" href="#_3-配置环境变量" aria-label="Permalink to &quot;3. 配置环境变量&quot;">​</a></h2><p>安装前需要先配置 <code>CCWS_IMAGE_API_KEY</code>。建议配置为长期环境变量，否则重启终端或 Codex 后可能需要重新设置。</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-Hz09b" id="tab-NW_RPf7" checked><label data-title="macOS / Linux 临时生效" for="tab-NW_RPf7">macOS / Linux 临时生效</label><input type="radio" name="group-Hz09b" id="tab-Mb1hDka"><label data-title="Windows PowerShell 临时生效" for="tab-Mb1hDka">Windows PowerShell 临时生效</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CCWS_IMAGE_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;你的 CCWSPro 生图 API Key&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">env:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">CCWS_IMAGE_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;你的 CCWSPro 生图 API Key&quot;</span></span></code></pre></div></div></div><p>长期配置可以这样设置：</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-X5_w2" id="tab-Wz9qyw8" checked><label data-title="macOS / Linux zsh" for="tab-Wz9qyw8">macOS / Linux zsh</label><input type="radio" name="group-X5_w2" id="tab-k7PTui5"><label data-title="macOS / Linux bash" for="tab-k7PTui5">macOS / Linux bash</label><input type="radio" name="group-X5_w2" id="tab-ai5KvOa"><label data-title="Windows PowerShell" for="tab-ai5KvOa">Windows PowerShell</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;export CCWS_IMAGE_API_KEY=&quot;你的 CCWSPro 生图 API Key&quot;&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.zshrc</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.zshrc</span></span></code></pre></div><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;export CCWS_IMAGE_API_KEY=&quot;你的 CCWSPro 生图 API Key&quot;&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.bashrc</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.bashrc</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]::SetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;CCWS_IMAGE_API_KEY&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;你的 CCWSPro 生图 API Key&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;User&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></div></div><p>Windows 长期配置后，需要重新打开 PowerShell 或重启 Codex，让新环境变量生效。</p><div class="warning custom-block"><p class="custom-block-title">注意</p><p>这个 Key 是生图技能使用的 Key，不要和普通聊天配置里的 <code>auth.json</code> 混在一起。安装器和生图技能都会读取 <code>CCWS_IMAGE_API_KEY</code>，如果没有配置，会停止安装或无法生图。</p></div><h2 id="_4-运行安装器" tabindex="-1">4. 运行安装器 <a class="header-anchor" href="#_4-运行安装器" aria-label="Permalink to &quot;4. 运行安装器&quot;">​</a></h2><p>进入解压后的安装包目录，再运行安装命令。</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-lgzjV" id="tab-By8fNKs" checked><label data-title="macOS / Linux" for="tab-By8fNKs">macOS / Linux</label><input type="radio" name="group-lgzjV" id="tab-8ypYpZv"><label data-title="Windows PowerShell" for="tab-8ypYpZv">Windows PowerShell</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 解压后的安装包目录</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python3</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --yes</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">cd 解压后的安装包目录</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">py </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> .\\install.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">yes</span></span></code></pre></div></div></div><p>安装器会执行这些操作：</p><ol><li>检查本机已有的生图技能。</li><li>检查 <code>CCWS_IMAGE_API_KEY</code> 是否已配置。</li><li>安装 <code>ccws-image-generation</code> 技能。</li><li>提示你新开 Codex 会话或重启 Codex。</li></ol><p>如果安装器提示本机已经有其他生图技能，建议先按提示处理，避免多个生图技能同时响应同一个任务。</p><h2 id="_5-重启-codex" tabindex="-1">5. 重启 Codex <a class="header-anchor" href="#_5-重启-codex" aria-label="Permalink to &quot;5. 重启 Codex&quot;">​</a></h2><p>安装完成后，新开一个 Codex 会话，或重启 Codex 客户端 / Codex CLI。</p><p>重启后再测试生图任务，不要在旧会话里直接测试。</p><h2 id="_6-测试生图" tabindex="-1">6. 测试生图 <a class="header-anchor" href="#_6-测试生图" aria-label="Permalink to &quot;6. 测试生图&quot;">​</a></h2><p>可以先用一个简单任务确认是否生效：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>帮我生成一张 16:9 的产品宣传图，主题是 AI 编程工具，画面要简洁、明亮、适合放在文档首页。</span></span></code></pre></div><p>如果需要图片编辑，可以把图片发给 Codex 后再描述修改要求：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>把这张图的背景替换成浅色办公桌面风格，主体保持不变。</span></span></code></pre></div><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="提示没有配置-ccws-image-api-key" tabindex="-1">提示没有配置 CCWS_IMAGE_API_KEY <a class="header-anchor" href="#提示没有配置-ccws-image-api-key" aria-label="Permalink to &quot;提示没有配置 CCWS_IMAGE_API_KEY&quot;">​</a></h3><p>说明当前终端没有读取到生图 API Key。重新执行环境变量配置命令后，再运行安装器。长期配置后，需要重新打开终端或重启 Codex。</p><h3 id="安装后-codex-仍然没有生图" tabindex="-1">安装后 Codex 仍然没有生图 <a class="header-anchor" href="#安装后-codex-仍然没有生图" aria-label="Permalink to &quot;安装后 Codex 仍然没有生图&quot;">​</a></h3><p>按顺序检查：</p><ol><li>是否已经新开 Codex 会话或重启 Codex。</li><li>安装器是否提示 <code>ccws-image-generation</code> 安装成功。</li><li><code>CCWS_IMAGE_API_KEY</code> 对应的 Key 是否支持 <code>gpt-image-2</code>。</li><li>本机是否存在其他生图技能导致冲突。</li></ol><h3 id="windows-提示找不到-py" tabindex="-1">Windows 提示找不到 py <a class="header-anchor" href="#windows-提示找不到-py" aria-label="Permalink to &quot;Windows 提示找不到 py&quot;">​</a></h3><p>说明 Windows 当前没有可用的 Python 启动器。请先安装 Python，再重新打开 PowerShell 执行安装命令。</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="https://github.com/xiaofengtongxue-lab/ccws-codex-image-skill" target="_blank" rel="noreferrer">CCWS Codex Image Skill 仓库</a></li><li><a href="https://github.com/xiaofengtongxue-lab/ccws-codex-image-skill/releases" target="_blank" rel="noreferrer">下载安装包</a></li></ul>`,45)])])}const g=i(l,[["render",p]]);export{k as __pageData,g as default};
